    fn test_key_definition_is_no_op() {
        let key = KeyDefinition::new(Position::new(0, 0), "KC_NO");
        assert!(key.is_no_op());

        let key = KeyDefinition::new(Position::new(0, 0), "KC_A");
        assert!(!key.is_no_op());
    }

